package com.lightevents.dashboard;
import com.lightevents.events.*; import com.lightevents.payments.TransactionRepository; import com.lightevents.profiles.UserProfileRepository; import org.springframework.web.bind.annotation.*; import java.time.*; import java.util.*; import java.util.stream.*;
@RestController @RequestMapping("/api/dashboard")
public class DashboardController { private final EventRepository events; private final AttendeeRepository attendees; private final ReservationRepository reservations; private final UserProfileRepository profiles; private final TransactionRepository tx; public DashboardController(EventRepository events, AttendeeRepository attendees, ReservationRepository reservations, UserProfileRepository profiles, TransactionRepository tx){this.events=events;this.attendees=attendees;this.reservations=reservations;this.profiles=profiles;this.tx=tx;} @GetMapping("/summary") public Map<String,Object> summary(){return Map.of("events",events.count(),"attendees",attendees.count(),"checkedIn",attendees.countByStatus(CheckInStatus.CHECKED_IN),"profiles",profiles.count(),"transactions",tx.count(),"markets",java.util.List.of("Côte d’Ivoire","Sénégal","Cameroun","RDC","Bénin","Togo"));}
 @GetMapping("/organizer") public Map<String,Object> organizer(@RequestParam(required=false) String email){ List<Event> own=events.findAll().stream().filter(e->email==null||email.isBlank()||email.equalsIgnoreCase(e.getOrganizerEmail())).toList(); List<Map<String,Object>> list=own.stream().map(e->{ List<Attendee> people=attendees.findByEventId(e.getId()); Map<String,Long> byCountry=people.stream().collect(Collectors.groupingBy(a->a.getCountryOfResidence()==null||a.getCountryOfResidence().isBlank()?"Non précisé":a.getCountryOfResidence(), Collectors.counting())); long seconds=Math.max(0, Duration.between(LocalDateTime.now(), e.getStartsAt()).toSeconds()); return Map.<String,Object>of("event",e,"participants",people,"reservations",reservations.findAll().stream().filter(r->Objects.equals(r.getEventId(),e.getId())).toList(),"participantCountries",byCountry,"countdownSeconds",seconds); }).toList(); return Map.of("events",list,"platformFeePercent",4.5); }}
